/**
 * Span is a single timed operation within a trace.
 */
export interface Span {
  trace_id: TraceID;
  span_id: SpanID;
  parent_id?: SpanID;
  name: string; // "orientation", "tool:web_search", "subagent:research"
  start_time: string;
  end_time?: string;
  duration_ms: number;
  attributes?: { [key: string]: unknown};
  error?: string;
  status: SpanStatus;
}
/**
 * SpanStatus is the outcome of a span.
 */
export type SpanStatus = string;
export const SpanStatusOK: SpanStatus = "ok";
export const SpanStatusError: SpanStatus = "error";
/**
 * Tracer collects spans for a single trace. Add it to ctx via WithTracer
 * and child operations will attach automatically.
 */
export interface Tracer {
}
